-- Migration 082: 自主訓練 P1 —— 配速等級表 + 課表庫(system seed)
CREATE TABLE IF NOT EXISTS pace_levels (
  id INT PRIMARY KEY, label TEXT NOT NULL, paces JSONB NOT NULL, enabled BOOLEAN NOT NULL DEFAULT TRUE);
CREATE TABLE IF NOT EXISTS workout_templates (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(), code TEXT UNIQUE NOT NULL, name TEXT NOT NULL,
  category TEXT NOT NULL, description TEXT NOT NULL DEFAULT '', segments JSONB NOT NULL,
  sort_order INT NOT NULL DEFAULT 0, enabled BOOLEAN NOT NULL DEFAULT TRUE, created_at TIMESTAMPTZ NOT NULL DEFAULT now());



ON CONFLICT (key) DO NOTHING;

